<?php
require_once __DIR__.'/../config.php';require_once __DIR__.'/../lib/layout.php';$p=db();requiere_login('');if(!tiene_rol(['SUPER_ADMIN','ADMIN','TI'])){http_response_code(403);exit('No autorizado.');}$msg=null;
if($_SERVER['REQUEST_METHOD']==='POST'){try{$tipo=$_POST['tipo']==='INSTALLER_URL'?'INSTALLER_URL':'WINDOWS_UPDATE';$serial=limpio($_POST['serial']??null);$params=$tipo==='INSTALLER_URL'?['url'=>trim($_POST['url']??''),'argumentos'=>trim($_POST['argumentos']??'/quiet')]:[];if($tipo==='INSTALLER_URL'&&!str_starts_with($params['url'],'https://'))throw new RuntimeException('El instalador debe estar en una URL HTTPS.');$p->prepare('INSERT INTO agente_ordenes(serial_objetivo,tipo,parametros_json,solicitado_por)VALUES(?,?,?,?)')->execute([$serial,$tipo,json_encode($params),usuario_actual()['nombre']??'Sistema']);$msg=['ok','Orden enviada a la cola. Se ejecutará cuando el agente reporte el equipo.'];}catch(Throwable $e){$msg=['error',$e->getMessage()];}}
$ordenes=$p->query('SELECT * FROM agente_ordenes ORDER BY id DESC LIMIT 100')->fetchAll(PDO::FETCH_ASSOC);$equipos=$p->query("SELECT serial,asignado_a,marca,modelo FROM inventario WHERE estado='ACTIVO' ORDER BY serial")->fetchAll(PDO::FETCH_ASSOC);layout_inicio('Órdenes del agente','Órdenes del agente','../');?><h1><?=icon('zap','icon-lg')?> Órdenes para agentes</h1><p class="subtitle">Actualizaciones y software aprobado. El agente devuelve el resultado al panel.</p><?php if($msg):?><div class="msg-<?=$msg[0]?>"><?=e($msg[1])?></div><?php endif;?><div class="panel"><form method="post"><label>Equipo (vacío = todos)</label><select name="serial"><option value="">Todos los equipos</option><?php foreach($equipos as $e):?><option value="<?=e($e['serial'])?>"><?=e($e['serial'].' · '.$e['asignado_a'].' · '.$e['marca'].' '.$e['modelo'])?></option><?php endforeach;?></select><label>Acción</label><select name="tipo" id="tipo"><option value="WINDOWS_UPDATE">Buscar e instalar actualizaciones de Windows</option><option value="INSTALLER_URL">Ejecutar instalador aprobado HTTPS</option></select><div id="urlBox" hidden><label>URL HTTPS del instalador</label><input type="url" name="url"><label>Argumentos silenciosos</label><input name="argumentos" value="/quiet"></div><button>Crear orden</button></form></div><div class="panel"><h3>Historial de órdenes</h3><table><tr><th>ID</th><th>Equipo</th><th>Tipo</th><th>Estado</th><th>Resultado</th><th>Fecha</th></tr><?php foreach($ordenes as $o):?><tr><td>#<?=$o['id']?></td><td><?=e($o['serial_objetivo']?:'Todos')?></td><td><?=e($o['tipo'])?></td><td><?=e($o['estado'])?></td><td><?=e($o['resultado']?:$o['error'])?></td><td><?=e($o['creado_en'])?></td></tr><?php endforeach;?></table></div><script>document.getElementById('tipo').onchange=e=>document.getElementById('urlBox').hidden=e.target.value!=='INSTALLER_URL';</script><?php layout_fin();
